import React, { useMemo, useState, useContext, useEffect } from "react";
import {
  View,
  Text,
  TextInput,
  ScrollView,
  Pressable,
  Alert,
  StyleSheet,
} from "react-native";
import { useTranslation } from "../../i18n";
import api from "../../services/api";
import { AppContext } from "../../../App";
import Header from "../../components/Header";

const COLORS = {
  primary: "#024A59",
  teal: "#1CA7AE",
  background: "#F6FAFB",
  card: "#FFFFFF",
  text: "#0b1a1f",
  muted: "#6B7280",
  error: "#EF4444",
  border: "#E5E7EB",
};

function isValidDateDDMMYYYY(s) {
  if (!s) return false;
  const m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s.trim());
  if (!m) return false;
  const dd = Number(m[1]);
  const mm = Number(m[2]);
  const yyyy = Number(m[3]);
  if (yyyy < 1900 || yyyy > 2100) return false;
  if (mm < 1 || mm > 12) return false;
  const daysInMonth = new Date(yyyy, mm, 0).getDate();
  return dd >= 1 && dd <= daysInMonth;
}

function ddmmyyyyToISO(s) {
  const m = /^(\d{2})\/(\d{2})\/(\d{4})$/.exec(s.trim());
  if (!m) return null;
  const dd = m[1];
  const mm = m[2];
  const yyyy = m[3];
  return `${yyyy}-${mm}-${dd}`;
}

function Card({ children, style }) {
  return <View style={[styles.card, style]}>{children}</View>;
}

function Label({ children, required }) {
  return (
    <Text style={styles.label}>
      {children}
      {required && <Text style={styles.required}> *</Text>}
    </Text>
  );
}

function ErrorText({ children }) {
  if (!children) return null;
  return <Text style={styles.error}>{children}</Text>;
}

function PillRadio({ label, selected, onPress }) {
  return (
    <Pressable
      onPress={onPress}
      style={({ pressed }) => [
        styles.pill,
        selected && styles.pillOn,
        pressed && styles.pillPressed,
      ]}
    >
      <Text style={[styles.pillText, selected && styles.pillTextOn]}>{label}</Text>
    </Pressable>
  );
}

function OptionRow({ label, selected, onPress }) {
  return (
    <Pressable
      onPress={onPress}
      style={({ pressed }) => [
        styles.optionRow,
        pressed && styles.optionRowPressed,
      ]}
    >
      <View style={[styles.dot, selected && styles.dotOn]}>
        {selected ? <View style={styles.dotInner} /> : null}
      </View>
      <Text style={styles.optionText}>{label}</Text>
    </Pressable>
  );
}

function CheckRow({ label, checked, onPress }) {
  return (
    <Pressable onPress={onPress} style={styles.checkRow}>
      <View style={[styles.checkBox, checked && styles.checkBoxOn]}>
        {checked ? <Text style={styles.checkMark}>✓</Text> : null}
      </View>
      <Text style={styles.checkLabel}>{label}</Text>
    </Pressable>
  );
}

export default function VehicleAdminInfoScreen({ route, navigation }) {
  const { verification, setVerification } = useContext(AppContext);
  const verificationId = verification?.verificationId;
  const { t } = useTranslation();

  // Load saved data from context on component mount
  const [form, setForm] = useState(() => {
    return (
      verification?.vehicleAdmin || {
        // ---- Document toggles (true = has doc / show + require fields) ----
        // CHANGED: Default all to true (checkboxes unchecked by default)
        hasTechInspectionDoc: true,
        hasBlueCardDoc: true,
        hasOwnerCatLicenseDoc: true,
        hasMunicipalityTaxDoc: true,
        hasDriverCapacityDoc: true,
        hasMacaronDoc: true,
        hasSecureBadgeDoc: true,

        // ---- Existing fields ----
        technicalInspectionValid: null,
        technicalInspectionDate: "",
        blueCardNumber: "",
        blueCardIssueDate: "",
        ownerCatLicenseNumber: "",
        ownerCatLicenseIssueDate: "",
        municipality: "",
        municipalityTaxNumber: "",
        taxisOperated: "",
        driverPhone: "",
        driverCapacityNumber: "",
        secureBadge: null,
        driversRelayCount: "",
        macaronNumber: "",
      }
    );
  });

  const [saving, setSaving] = useState(false);

  // Auto-save form data to context with debouncing
  useEffect(() => {
    const saveTimeout = setTimeout(() => {
      const hasData = Object.values(form).some((value) => {
        if (value === null) return false;
        if (typeof value === "string") return value.trim().length > 0;
        return true;
      });

      if (hasData) {
        setVerification((prev) => ({
          ...prev,
          vehicleAdmin: form,
        }));
      }
    }, 500);

    return () => clearTimeout(saveTimeout);
  }, [form, setVerification]);

  const municipalityOptions = useMemo(
    () => [
      t("vehicleAdmin.arr1"),
      t("vehicleAdmin.arr2"),
      t("vehicleAdmin.arr3"),
      t("vehicleAdmin.arr4"),
      t("vehicleAdmin.arr5"),
      t("vehicleAdmin.arr6"),
      t("vehicleAdmin.arr7"),
    ],
    [t]
  );

  const errors = useMemo(() => {
    const e = {};

    // --------------------
    // Required fields
    // --------------------

    // Technical inspection (only if user has the doc)
    if (form.hasTechInspectionDoc) {
      if (form.technicalInspectionValid === null) {
        e.technicalInspectionValid = t("common.required");
      }

      if (form.technicalInspectionValid === true) {
        if (!form.technicalInspectionDate.trim()) {
          e.technicalInspectionDate = t("common.required");
        } else if (!isValidDateDDMMYYYY(form.technicalInspectionDate)) {
          e.technicalInspectionDate = t("common.invalidDate");
        }
      } else if (
        form.technicalInspectionDate &&
        !isValidDateDDMMYYYY(form.technicalInspectionDate)
      ) {
        e.technicalInspectionDate = t("common.invalidDate");
      }
    } else {
      // if no doc, ignore validation even if date typed
    }

    // Blue card (only if doc exists)
    if (form.hasBlueCardDoc) {
      if (!form.blueCardNumber.trim()) e.blueCardNumber = t("common.required");
      if (!form.blueCardIssueDate.trim()) e.blueCardIssueDate = t("common.required");
      if (form.blueCardIssueDate && !isValidDateDDMMYYYY(form.blueCardIssueDate))
        e.blueCardIssueDate = t("common.invalidDate");
    }

    // Owner category license (only if doc exists)
    if (form.hasOwnerCatLicenseDoc) {
      if (!form.ownerCatLicenseNumber.trim())
        e.ownerCatLicenseNumber = t("common.required");
      if (!form.ownerCatLicenseIssueDate.trim())
        e.ownerCatLicenseIssueDate = t("common.required");
      if (
        form.ownerCatLicenseIssueDate &&
        !isValidDateDDMMYYYY(form.ownerCatLicenseIssueDate)
      )
        e.ownerCatLicenseIssueDate = t("common.invalidDate");
    }

    // Municipality is NOT document-based (keep required)
    if (!form.municipality.trim()) e.municipality = t("common.required");

    // Municipality tax number (doc-based)
    if (form.hasMunicipalityTaxDoc) {
      if (!form.municipalityTaxNumber.trim())
        e.municipalityTaxNumber = t("common.required");
    }

    // taxis operated (keep required)
    if (!form.taxisOperated.trim()) e.taxisOperated = t("common.required");

    // driver phone (keep required)
    if (!form.driverPhone.trim()) e.driverPhone = t("common.required");

    // driver capacity number (doc-based)
    if (form.hasDriverCapacityDoc) {
      if (!form.driverCapacityNumber.trim())
        e.driverCapacityNumber = t("common.required");
    }

    // secure badge (doc-based)
    if (form.hasSecureBadgeDoc) {
      if (form.secureBadge === null) e.secureBadge = t("common.required");
    }

    // drivers relay count (keep required)
    if (!form.driversRelayCount.trim()) e.driversRelayCount = t("common.required");

    // macaron number (doc-based)
    if (form.hasMacaronDoc) {
      if (!form.macaronNumber.trim()) e.macaronNumber = t("common.required");
    }

    // --------------------
    // Numeric validation
    // --------------------
    if (form.taxisOperated && isNaN(Number(form.taxisOperated)))
      e.taxisOperated = t("vehicleAdmin.invalidNumber");

    if (form.driversRelayCount && isNaN(Number(form.driversRelayCount)))
      e.driversRelayCount = t("vehicleAdmin.invalidNumber");

    return e;
  }, [form, t]);

  const canContinue = Object.keys(errors).length === 0 && !saving;

  const update = (key, value) => {
    setForm((p) => ({ ...p, [key]: value }));
  };

  const submit = async () => {
    if (!canContinue) {
      Alert.alert(t("vehicleAdmin.form"), t("vehicleAdmin.correctFields"));
      return;
    }

    setSaving(true);
    try {
      await api.put(`/verification/${verificationId}/extra`, {
        vehicle: {
          blueCardNumber: form.hasBlueCardDoc ? form.blueCardNumber.trim() : null,
          blueCardIssueDate: form.hasBlueCardDoc
            ? ddmmyyyyToISO(form.blueCardIssueDate)
            : null,
          municipality: form.municipality.trim(),
          municipalityTaxNumber: form.hasMunicipalityTaxDoc
            ? form.municipalityTaxNumber.trim()
            : null,
          macaronNumber: form.hasMacaronDoc ? form.macaronNumber.trim() : null,
        },
        owner: {
          categoryLicenseNumber: form.hasOwnerCatLicenseDoc
            ? form.ownerCatLicenseNumber.trim()
            : null,
          categoryLicenseIssueDate: form.hasOwnerCatLicenseDoc
            ? ddmmyyyyToISO(form.ownerCatLicenseIssueDate)
            : null,
          taxisOperated: Number(form.taxisOperated),
        },
        driver: {
          phone: form.driverPhone.trim(),
          capacityNumber: form.hasDriverCapacityDoc
            ? form.driverCapacityNumber.trim()
            : null,
        },
        survey: {
          technicalInspectionValid: form.hasTechInspectionDoc
            ? form.technicalInspectionValid
            : null,
          technicalInspectionDate:
            form.hasTechInspectionDoc && form.technicalInspectionDate
              ? ddmmyyyyToISO(form.technicalInspectionDate)
              : null,
          secureBadge: form.hasSecureBadgeDoc ? form.secureBadge : null,
          driversRelayCount: Number(form.driversRelayCount),
        },
      });

      // Clear saved vehicle admin data after successful submission
      setVerification((prev) => ({
        ...prev,
        vehicleAdmin: null,
      }));

      navigation.navigate("car_registration_doc_upload");
    } catch (err) {
      console.error(err);
      Alert.alert(t("vehicleAdmin.error"), t("vehicleAdmin.serverError"));
    } finally {
      setSaving(false);
    }
  };

  // Back navigation
  const handleBack = () => {
    navigation.navigate("vehicle_not_found_info");
  };

  return (
    <View style={styles.screen}>
      <Header />
      <ScrollView
        contentContainerStyle={styles.scrollContent}
        keyboardShouldPersistTaps="handled"
        showsVerticalScrollIndicator={false}
      >
        {/* Back Button */}
        <Pressable style={styles.backButton} onPress={handleBack}>
          <Text style={styles.backButtonIcon}>←</Text>
        </Pressable>

        {/* Header */}
        <View style={styles.header}>
          <Text style={styles.title}>{t("vehicleAdmin.title")}</Text>
          <Text style={styles.subtitle}>{t("vehicleAdmin.subtitle")}</Text>
        </View>

        {/* Tech Inspection Section */}
        <Card>
          <Text style={styles.sectionTitle}>{t("vehicleAdmin.techInspection")}</Text>

          {/* Checkbox label updated to be more intuitive */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveTechInspection")}
            checked={!form.hasTechInspectionDoc}
            onPress={() => {
              const willHave = !form.hasTechInspectionDoc;
              update("hasTechInspectionDoc", willHave);

              if (!willHave) {
                // user does NOT have the doc → clear + unrequire
                update("technicalInspectionValid", null);
                update("technicalInspectionDate", "");
              }
            }}
          />

          {form.hasTechInspectionDoc && (
            <>
              <Label required>{t("vehicleAdmin.techInspectionValid")}</Label>
              <View style={styles.pillRow}>
                <PillRadio
                  label={t("common.yes")}
                  selected={form.technicalInspectionValid === true}
                  onPress={() => update("technicalInspectionValid", true)}
                />
                <PillRadio
                  label={t("common.no")}
                  selected={form.technicalInspectionValid === false}
                  onPress={() => update("technicalInspectionValid", false)}
                />
              </View>
              <ErrorText>{errors.technicalInspectionValid}</ErrorText>

              <Label>{t("vehicleAdmin.techInspectionDate")}</Label>
              <TextInput
                value={form.technicalInspectionDate}
                onChangeText={(v) => update("technicalInspectionDate", v)}
                placeholder="JJ/MM/AAAA"
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.technicalInspectionDate && styles.inputError,
                ]}
              />
              <ErrorText>{errors.technicalInspectionDate}</ErrorText>
            </>
          )}
        </Card>

        {/* Vehicle Section */}
        <Card>
          <Text style={styles.sectionTitle}>{t("vehicleAdmin.vehicle")}</Text>

          {/* Blue Card */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveBlueCard")}
            checked={!form.hasBlueCardDoc}
            onPress={() => {
              const willHave = !form.hasBlueCardDoc;
              update("hasBlueCardDoc", willHave);

              if (!willHave) {
                update("blueCardNumber", "");
                update("blueCardIssueDate", "");
              }
            }}
          />

          {form.hasBlueCardDoc && (
            <>
              <Label required>{t("vehicleAdmin.blueCardNumber")}</Label>
              <TextInput
                value={form.blueCardNumber}
                onChangeText={(v) => update("blueCardNumber", v)}
                placeholder={t("vehicleAdmin.blueCardNumberPlaceholder")}
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.blueCardNumber && styles.inputError,
                ]}
              />
              <ErrorText>{errors.blueCardNumber}</ErrorText>

              <Label required>{t("vehicleAdmin.blueCardIssueDate")}</Label>
              <TextInput
                value={form.blueCardIssueDate}
                onChangeText={(v) => update("blueCardIssueDate", v)}
                placeholder="JJ/MM/AAAA"
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.blueCardIssueDate && styles.inputError,
                ]}
              />
              <ErrorText>{errors.blueCardIssueDate}</ErrorText>
            </>
          )}

          {/* Macaron */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveMacaron")}
            checked={!form.hasMacaronDoc}
            onPress={() => {
              const willHave = !form.hasMacaronDoc;
              update("hasMacaronDoc", willHave);

              if (!willHave) {
                update("macaronNumber", "");
              }
            }}
          />

          {form.hasMacaronDoc && (
            <>
              <Label required>{t("vehicleAdmin.macaronNumber")}</Label>
              <TextInput
                value={form.macaronNumber}
                onChangeText={(v) => update("macaronNumber", v)}
                placeholder={t("vehicleAdmin.macaronNumberPlaceholder")}
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.macaronNumber && styles.inputError,
                ]}
              />
              <ErrorText>{errors.macaronNumber}</ErrorText>
            </>
          )}
        </Card>

        {/* Owner Section */}
        <Card>
          <Text style={styles.sectionTitle}>{t("vehicleAdmin.owner")}</Text>

          {/* Owner Category License */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveOwnerLicense")}
            checked={!form.hasOwnerCatLicenseDoc}
            onPress={() => {
              const willHave = !form.hasOwnerCatLicenseDoc;
              update("hasOwnerCatLicenseDoc", willHave);

              if (!willHave) {
                update("ownerCatLicenseNumber", "");
                update("ownerCatLicenseIssueDate", "");
              }
            }}
          />

          {form.hasOwnerCatLicenseDoc && (
            <>
              <Label required>{t("vehicleAdmin.ownerCatLicenseNumber")}</Label>
              <TextInput
                value={form.ownerCatLicenseNumber}
                onChangeText={(v) => update("ownerCatLicenseNumber", v)}
                placeholder={t("vehicleAdmin.ownerCatLicenseNumberPlaceholder")}
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.ownerCatLicenseNumber && styles.inputError,
                ]}
              />
              <ErrorText>{errors.ownerCatLicenseNumber}</ErrorText>

              <Label required>{t("vehicleAdmin.ownerCatLicenseIssueDate")}</Label>
              <TextInput
                value={form.ownerCatLicenseIssueDate}
                onChangeText={(v) => update("ownerCatLicenseIssueDate", v)}
                placeholder="JJ/MM/AAAA"
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.ownerCatLicenseIssueDate && styles.inputError,
                ]}
              />
              <ErrorText>{errors.ownerCatLicenseIssueDate}</ErrorText>
            </>
          )}

          <Label required>{t("vehicleAdmin.municipality")}</Label>
          <View style={styles.optionsBox}>
            {municipalityOptions.map((opt) => (
              <OptionRow
                key={opt}
                label={opt}
                selected={form.municipality === opt}
                onPress={() => update("municipality", opt)}
              />
            ))}
          </View>
          <ErrorText>{errors.municipality}</ErrorText>

          {/* Municipality tax number (doc-based) */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveMunicipalityTax")}
            checked={!form.hasMunicipalityTaxDoc}
            onPress={() => {
              const willHave = !form.hasMunicipalityTaxDoc;
              update("hasMunicipalityTaxDoc", willHave);

              if (!willHave) {
                update("municipalityTaxNumber", "");
              }
            }}
          />

          {form.hasMunicipalityTaxDoc && (
            <>
              <Label required>{t("vehicleAdmin.municipalityTaxNumber")}</Label>
              <TextInput
                value={form.municipalityTaxNumber}
                onChangeText={(v) => update("municipalityTaxNumber", v)}
                placeholder={t("vehicleAdmin.municipalityTaxNumberPlaceholder")}
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.municipalityTaxNumber && styles.inputError,
                ]}
              />
              <ErrorText>{errors.municipalityTaxNumber}</ErrorText>
            </>
          )}

          <Label required>{t("vehicleAdmin.taxisOperated")}</Label>
          <TextInput
            value={form.taxisOperated}
            onChangeText={(v) => update("taxisOperated", v)}
            placeholder={t("vehicleAdmin.taxisOperatedPlaceholder")}
            keyboardType="numeric"
            placeholderTextColor={COLORS.muted}
            style={[styles.input, errors.taxisOperated && styles.inputError]}
          />
          <ErrorText>{errors.taxisOperated}</ErrorText>
        </Card>

        {/* Driver Section */}
        <Card>
          <Text style={styles.sectionTitle}>{t("vehicleAdmin.driver")}</Text>

          <Label required>{t("vehicleAdmin.driverPhone")}</Label>
          <TextInput
            value={form.driverPhone}
            onChangeText={(v) => update("driverPhone", v)}
            placeholder={t("vehicleAdmin.driverPhonePlaceholder")}
            keyboardType="phone-pad"
            placeholderTextColor={COLORS.muted}
            style={[styles.input, errors.driverPhone && styles.inputError]}
          />
          <ErrorText>{errors.driverPhone}</ErrorText>

          {/* Driver capacity (doc-based) */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveDriverCapacity")}
            checked={!form.hasDriverCapacityDoc}
            onPress={() => {
              const willHave = !form.hasDriverCapacityDoc;
              update("hasDriverCapacityDoc", willHave);

              if (!willHave) {
                update("driverCapacityNumber", "");
              }
            }}
          />

          {form.hasDriverCapacityDoc && (
            <>
              <Label required>{t("vehicleAdmin.driverCapacityNumber")}</Label>
              <TextInput
                value={form.driverCapacityNumber}
                onChangeText={(v) => update("driverCapacityNumber", v)}
                placeholder={t("vehicleAdmin.driverCapacityNumberPlaceholder")}
                placeholderTextColor={COLORS.muted}
                style={[
                  styles.input,
                  errors.driverCapacityNumber && styles.inputError,
                ]}
              />
              <ErrorText>{errors.driverCapacityNumber}</ErrorText>
            </>
          )}

          {/* Secure badge (doc-based) */}
          <CheckRow
            label={t("vehicleAdminDocs.iDontHaveSecureBadge")}
            checked={!form.hasSecureBadgeDoc}
            onPress={() => {
              const willHave = !form.hasSecureBadgeDoc;
              update("hasSecureBadgeDoc", willHave);

              if (!willHave) {
                update("secureBadge", null);
              }
            }}
          />

          {form.hasSecureBadgeDoc && (
            <>
              <Label required>{t("vehicleAdmin.secureBadge")}</Label>
              <View style={styles.pillRow}>
                <PillRadio
                  label={t("common.yes")}
                  selected={form.secureBadge === true}
                  onPress={() => update("secureBadge", true)}
                />
                <PillRadio
                  label={t("common.no")}
                  selected={form.secureBadge === false}
                  onPress={() => update("secureBadge", false)}
                />
              </View>
              <ErrorText>{errors.secureBadge}</ErrorText>
            </>
          )}

          <Label required>{t("vehicleAdmin.driversRelayCount")}</Label>
          <TextInput
            value={form.driversRelayCount}
            onChangeText={(v) => update("driversRelayCount", v)}
            placeholder={t("vehicleAdmin.driversRelayCountPlaceholder")}
            keyboardType="numeric"
            placeholderTextColor={COLORS.muted}
            style={[
              styles.input,
              errors.driversRelayCount && styles.inputError,
            ]}
          />
          <ErrorText>{errors.driversRelayCount}</ErrorText>
        </Card>

        {/* Continue Button */}
        <Pressable
          onPress={submit}
          disabled={!canContinue}
          style={({ pressed }) => [
            styles.cta,
            !canContinue && styles.ctaDisabled,
            pressed && styles.ctaPressed,
          ]}
        >
          <Text style={styles.ctaText}>
            {saving ? t("vehicleAdmin.saving") : t("common.continue")}
          </Text>
        </Pressable>

        <View style={{ height: 32 }} />
      </ScrollView>
    </View>
  );
}

